SELECT SUBSTR(a.geo_id, -6) AS tract_code FROM (SELECT geo_id, median_income AS income_2015 FROM `bigquery-public-data.census_bureau_acs.censustract_2015_5yr` WHERE SUBSTR(geo_id, 1, 2) = '06') a JOIN (SELECT geo_id, median_income AS income_2018 FROM `bigquery-public-data.census_bureau_acs.censustract_2018_5yr` WHERE SUBSTR(geo_id, 1, 2) = '06') b ON a.geo_id = b.geo_id ORDER BY (b.income_2018 - a.income_2015) DESC LIMIT 1